BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?param ?name ?type WHERE {
  ?elem vocab:NamedElement_name "offloadSensorOffsets%20Cmd" .
  ?elem vocab:Element_ownedElement ?param .
  ?param rdf:type vocab:parameter .
  OPTIONAL { ?param vocab:NamedElement_name ?name }
  OPTIONAL { ?param rdf:type ?type }
}

