PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?propName ?val WHERE {
  ?elemVal vocab:ElementValue_element <http://api.koneksys.com/cameo/TMT/hierarchyelement/TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::DRD%20APS::APS%20Requirements::Performance%20Requirements::Tip/Tilt%20and%20Phasing%20Performance%20Requirements::Segment%20tip/tilt%20measurement%20and%20M2%20misalignment%20error> .
  ?elemVal ?prop ?val .
  OPTIONAL { ?val vocab:NamedElement_name ?propName }
}
LIMIT 100

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?instance ?slot ?definingFeature ?featName ?val ?valName WHERE {
  ?elem vocab:NamedElement_name "Segment%20tip/tilt%20measurement%20and%20M2%20misalignment%20error" .
  ?elem vocab:Element_appliedStereotypeInstance ?instance .
  ?instance rdf:type vocab:instance%20specification .
  ?instance vocab:InstanceSpecification_slot ?slot .
  OPTIONAL { 
    ?slot vocab:Slot_definingFeature ?definingFeature .
    ?definingFeature vocab:NamedElement_name ?featName .
  }
  OPTIONAL { 
    ?slot vocab:Slot_value ?val .
    ?val vocab:NamedElement_name ?valName .
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?slot ?definingFeature ?featName ?val ?valName ?litVal WHERE {
  ?elem vocab:NamedElement_name "Segment%20tip/tilt%20measurement%20and%20M2%20misalignment%20error" .
  ?elem vocab:Element_appliedStereotypeInstance ?instance .
  ?instance vocab:InstanceSpecification_slot ?slot .
  OPTIONAL { 
    ?slot vocab:Slot_definingFeature ?definingFeature .
    ?definingFeature vocab:NamedElement_name ?featName .
  }
  OPTIONAL { 
    ?slot vocab:Slot_value ?val .
    OPTIONAL { ?val vocab:NamedElement_name ?valName }
    OPTIONAL { ?val vocab:LiteralString_value ?litVal }
    OPTIONAL { ?val vocab:LiteralReal_value ?realVal }
    OPTIONAL { ?val vocab:LiteralInteger_value ?intVal }
  }
}
LIMIT 100

BASE <http://api.koneksys.com/cameo/>
